@using sv_6e666cb2e1f14508a89f26bcf03e69e6.Models

<button class="channel-item @(IsActive ? "active" : "")"
        @onclick="() => OnSelected.InvokeAsync(Channel.Id)">
    <div class="channel-name"># @Channel.Name</div>
    <div class="channel-desc">@TruncateDescription(Channel.Description)</div>
    @if (Channel.UnreadCount > 0)
    {
        <span class="unread-badge">@Channel.UnreadCount</span>
    }
</button>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelected { get; set; }

    private static string TruncateDescription(string desc)
        => desc.Length > 40 ? desc[..37] + "..." : desc;
}

.channel-item {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    width: 100%;
    padding: 0.6rem 0.75rem;
    border: none;
    background: none;
    cursor: pointer;
    text-align: left;
    border-radius: 6px;
    transition: background 0.1s;
    gap: 0;
}

.channel-item:hover {
    background: #3a3c4e;
}

.channel-item.active {
    background: #5865f2;
    color: #fff;
}

.channel-name {
    flex: 1;
    font-weight: 600;
    font-size: 0.9rem;
    color: #ddd;
}

.channel-item.active .channel-name {
    color: #fff;
}

.channel-desc {
    width: 100%;
    font-size: 0.75rem;
    color: #999;
    overflow: hidden;
    white-space: nowrap;
    text-overflow: ellipsis;
}

.channel-item.active .channel-desc {
    color: rgba(255, 255, 255, 0.75);
}

.unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 0.1rem 0.45rem;
    border-radius: 10px;
    min-width: 1.2rem;
    text-align: center;
}

