arguments.file_text:
@using sv_6e666cb2e1f14508a89f26bcf03e69e6.Models

<nav class="channel-sidebar">
    <h2 class="sidebar-title">Channels</h2>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</nav>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    background: #2b2d42;
    color: #ddd;
    height: 100%;
    overflow: hidden;
}

.sidebar-title {
    padding: 1rem 0.75rem 0.5rem;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    border-bottom: 1px solid #3a3c4e;
    margin: 0;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem;
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
}

@using sv_6e666cb2e1f14508a89f26bcf03e69e6.Models

<div class="message-list" @ref="_scrollContainer" @onscroll="HandleScroll">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages...</div>
    }

    @foreach (var message in Messages)
    {
        <MessageItem Message="message"
                     ReplyCount="GetReplyCount(message.Id)"
                     OnReplyClicked="OnReplyClicked"
                     OnThreadClicked="OnThreadClicked"
                     OnReactionAdded="OnReactionAdded" />
    }
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<int> OnThreadClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    [Inject] private IJSRuntime JS { get; set; } = default!;

    private ElementReference _scrollContainer;
    private bool _shouldScrollToBottom = true;
    private int _previousMessageCount;

    private int GetReplyCount(int messageId)
        => ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task HandleScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("eval",
            $"document.querySelector('[_bl_{_scrollContainer.Id}]')?.scrollTop ?? 0");

        if (scrollTop < 50 && !IsLoadingMore)
        {
            _shouldScrollToBottom = false;
            await OnLoadMore.InvokeAsync();
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender || (_shouldScrollToBottom && Messages.Count != _previousMessageCount))
        {
            await JS.InvokeVoidAsync("eval",
                $"(() => {{ var el = document.querySelector('[_bl_{_scrollContainer.Id}]'); if(el) el.scrollTop = el.scrollHeight; }})()");
            _previousMessageCount = Messages.Count;
        }
    }
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem 0;
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
}

.loading-indicator {
    text-align: center;
    padding: 0.75rem;
    font-size: 0.8rem;
    color: #999;
}

@using sv_6e666cb2e1f14508a89f26bcf03e69e6.Models

<section class="message-area">
    @if (Channel is not null)
    {
        <div class="area-header">
            <h2># @Channel.Name</h2>
            <span class="header-desc">@Channel.Description</span>
        </div>

        <MessageList Messages="Messages"
                     ThreadReplyCounts="ThreadReplyCounts"
                     IsLoadingMore="IsLoadingMore"
                     OnLoadMore="OnLoadMore"
                     OnReplyClicked="OnReplyClicked"
                     OnThreadClicked="OnThreadClicked"
                     OnReactionAdded="OnReactionAdded" />

        <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                      ButtonLabel="Send"
                      OnSubmit="OnSendMessage" />
    }
    else
    {
        <div class="empty-state">Select a channel to start chatting</div>
    }
</section>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<int> OnThreadClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    overflow: hidden;
}

.area-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.area-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #1a1a2e;
}

.header-desc {
    font-size: 0.8rem;
    color: #777;
}

.empty-state {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    color: #999;
    font-size: 1.1rem;
}

@using sv_6e666cb2e1f14508a89f26bcf03e69e6.Models

@if (IsOpen && RootMessage is not null)
{
    <aside class="thread-panel">
        <div class="thread-header">
            <h3>Thread</h3>
            <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
        </div>

        <div class="thread-root">
            <MessageItem Message="RootMessage" ShowActions="false" />
        </div>

        <div class="thread-replies">
            @if (Replies.Count > 0)
            {
                <div class="replies-divider">@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</div>
            }
            @foreach (var reply in Replies)
            {
                <MessageItem Message="reply" ShowActions="false" />
            }
        </div>

        <MessageInput Placeholder="Reply..."
                      ButtonLabel="Reply"
                      OnSubmit="OnSendReply" />
    </aside>
}

@code {
