+    <div class="main-panel">
+        <MessageArea Channel="_selectedChannel"
+                     Messages="_messages"
+                     ThreadReplyCounts="_threadReplyCounts"
+                     IsLoadingMore="_isLoadingMore"
+                     OnLoadMore="LoadOlderMessagesAsync"
+                     OnSendMessage="SendMessageAsync"
+                     OnReplyClicked="OpenThreadAsync"
+                     OnThreadClicked="OpenThreadAsync"
+                     OnReactionAdded="AddReactionAsync" />
+    </div>
+
+    <div class="thread-container">
+        <ThreadPanel IsOpen="IsThreadOpen"
+                     RootMessage="_threadRootMessage"
+                     Replies="_threadReplies"
+                     OnClose="CloseThread"
+                     OnSendReply="SendThreadReplyAsync" />
+    </div>
+</div>
+
+@code {
+    [Inject] private IChatService ChatService { get; set; } = default!;
+
+    private List<Channel> _channels = [];
+    private List<Message> _messages = [];
+    private Dictionary<int, int> _threadReplyCounts = [];
+    private int _selectedChannelId;
+    private Channel? _selectedChannel;
+    private bool _isLoadingMore;
+
+    // Thread state
+    private Message? _threadRootMessage;
+    private List<Message> _threadReplies = [];
+    private bool IsThreadOpen => _threadRootMessage is not null;
+
+    private const int PageSize = 30;
+
+    protected override async Task OnInitializedAsync()
+    {
+        _channels = await ChatService.GetChannelsAsync();
+
+        if (_channels.Count > 0)
+        {
+            await SelectChannelAsync(_channels[0].Id);
+        }
+    }
+
+    private async Task SelectChannelAsync(int channelId)
+    {
+        _selectedChannelId = channelId;
+        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
+        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
+        _threadReplyCounts = await BuildThreadReplyCountsAsync();
+
+        await ChatService.MarkChannelReadAsync(channelId);
+        UpdateChannelUnreadCount(channelId);
+
+        CloseThread();
+    }
+
+    private async Task LoadOlderMessagesAsync()
+    {
+        if (_isLoadingMore || _selectedChannel is null) return;
+
+        _isLoadingMore = true;
+        StateHasChanged();
+
+        var older = await ChatService.GetMessagesAsync(_selectedChannelId, _messages.Count, PageSize);
+        if (older.Count > 0)
+        {
+            _messages.InsertRange(0, older);
+            _threadReplyCounts = await BuildThreadReplyCountsAsync();
+        }
+
+        _isLoadingMore = false;
+    }
+
+    private async Task SendMessageAsync(string content)
+    {
+        if (_selectedChannel is null) return;
+
+        var message = await ChatService.SendMessageAsync(_selectedChannelId, content, null);
+        _messages.Add(message);
+    }
+
+    private async Task OpenThreadAsync(int messageId)
+    {
+        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
+        if (_threadRootMessage is null) return;
+
+        var threadMessages = await ChatService.GetThreadAsync(messageId);
+        _threadReplies = threadMessages.Where(m => m.Id != messageId).ToList();
+    }
+
+    private void CloseThread()
+    {
+        _threadRootMessage = null;
+        _threadReplies = [];
+    }
+
+    private async Task SendThreadReplyAsync(string content)
+    {
+        if (_threadRootMessage is null) return;
+
+        var reply = await ChatService.SendMessageAsync(
+            _selectedChannelId, content, _threadRootMessage.Id);
+
+        _threadReplies.Add(reply);
+        _messages.Add(reply);
+
+        // Update thread reply count
+        _threadReplyCounts[_threadRootMessage.Id] =
+            _threadReplyCounts.GetValueOrDefault(_threadRootMessage.Id) + 1;
+    }
+
+    private async Task AddReactionAsync((int MessageId, string Emoji) args)
+    {
+        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
+
+        // Optimistic update: add reaction locally
+        var message = _messages.FirstOrDefault(m => m.Id == args.MessageId);
+        if (message is null) return;
+
+        var existing = message.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
+        if (existing is not null)
+        {
+            if (!existing.Users.Contains("You"))
+                existing.Users.Add("You");
+        }
+        else
+        {
+            message.Reactions.Add(new Reaction(args.Emoji, ["You"]));
+        }
+    }
+
+    private async Task<Dictionary<int, int>> BuildThreadReplyCountsAsync()
+    {
+        // Count messages that are replies to root messages in the current view
+        var rootIds = _messages
+            .Where(m => m.ReplyToId is null)
+            .Select(m => m.Id)
+            .ToHashSet();
+
+        var counts = new Dictionary<int, int>();
+        foreach (var rootId in rootIds)
+        {
+            var replyCount = _messages.Count(m => m.ReplyToId == rootId);
+            if (replyCount > 0)
+                counts[rootId] = replyCount;
+        }
+
+        return counts;
+    }
+
+    private void UpdateChannelUnreadCount(int channelId)
+    {
+        var index = _channels.FindIndex(c => c.Id == channelId);
+        if (index >= 0)
+        {
+            var ch = _channels[index];
+            _channels[index] = ch with { UnreadCount = 0 };
+        }
+    }
+}
+

